result_list=[]
attraction_name_set=set()
for activity in allactivities(plan):
  if activity_type(activity)=='attraction': attraction_name_set.add(activity_position(activity))
result=({"Columbia Circle", "Expo Culture Park", "Shanghai Heartbreak Museum"}<=attraction_name_set)
result_list.append(result)
restaurant_name_set=set()
for activity in allactivities(plan):
  if activity_type(activity) in ['breakfast', 'lunch', 'dinner']: restaurant_name_set.add(activity_position(activity))
result=not({"The Ritz-Carlton Shanghai, Pudong - Scena di Angelo"}&restaurant_name_set)
result_list.append(result)
result=False
for r in result_list:
  result=result or r

